        self.events = []
        self.overlaps = []
    def book(self, startTime, endTime):
        for s, e in self.overlaps:
            if startTime < e and s < endTime:
                return False
        for s, e in self.events:
            if startTime < e and s < endTime:
                self.overlaps.append((max(startTime, s), min(endTime, e)))
        self.events.append((startTime, endTime))
        return True

