class MyCalendarTwo {
    constructor() {
        this.events = [];
        this.overlaps = [];
    }
    book(startTime, endTime) {
        for (const [s, e] of this.overlaps) {
            if (startTime < e && s < endTime) return false;
        }
        for (const [s, e] of this.events) {
            if (startTime < e && s < endTime) {
                this.overlaps.push([Math.max(startTime, s), Math.min(endTime, e)]);
            }
        }
        this.events.push([startTime, endTime]);
        return true;
    }
}
